  1→import { Hono } from 'hono';
  2→import { streamSSE } from 'hono/streaming';
  3→import { getDb } from '@code-insights/cli/db/client';
  4→import { trackEvent, captureError } from '@code-insights/cli/utils/telemetry';
  5→import { parseIntParam } from '../utils.js';
  6→import { loadLLMConfig, isLLMConfigured } from '../llm/client.js';
  7→import { analyzeSession, analyzePromptQuality, findRecurringInsights } from '../llm/analysis.js';
  8→import type { SQLiteMessageRow, SessionData } from '../llm/analysis.js';
  9→
 10→const app = new Hono();
 11→
 12→// POST /api/analysis/session
 13→// Body: { sessionId: string }
 14→// Fetches session + messages from SQLite, runs LLM analysis, saves insights, returns results.
 15→app.post('/session', async (c) => {
 16→  if (!isLLMConfigured()) {
 17→    return c.json({
 18→      success: false,
 19→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 20→    }, 400);
 21→  }
 22→
 23→  const body = await c.req.json<{ sessionId?: string }>();
 24→  if (!body.sessionId || typeof body.sessionId !== 'string') {
 25→    return c.json({ error: 'Missing required field: sessionId' }, 400);
 26→  }
 27→
 28→  const db = getDb();
 29→
 30→  const session = db.prepare(`
 31→    SELECT id, project_id, project_name, project_path, summary, ended_at
 32→    FROM sessions WHERE id = ?
 33→  `).get(body.sessionId) as SessionData | undefined;
 34→
 35→  if (!session) {
 36→    return c.json({ error: 'Session not found' }, 404);
 37→  }
 38→
 39→  const messages = db.prepare(`
 40→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
 41→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
 42→  `).all(body.sessionId) as SQLiteMessageRow[];
 43→
 44→  const llmConfig = loadLLMConfig();
 45→  const startTime = Date.now();
 46→  const result = await analyzeSession(session, messages);
 47→  const baseProperties = {
 48→    type: 'session',
 49→    llm_provider: llmConfig?.provider,
 50→    llm_model: llmConfig?.model,
 51→    duration_ms: Date.now() - startTime,
 52→    success: result.success,
 53→  };
 54→  if (!result.success) {
 55→    const errorProperties = {
 56→      ...baseProperties,
 57→      error_type: result.error_type,
 58→      error_message: result.error,
 59→    };
 60→    trackEvent('analysis_run', errorProperties);
 61→    captureError(new Error(result.error ?? 'analysis_run failed'), errorProperties);
 62→  } else {
 63→    trackEvent('analysis_run', baseProperties);
 64→    trackEvent('insight_generated', {
 65→      type: 'session',
 66→      count: result.insights.length,
 67→    });
 68→  }
 69→  return c.json(result, result.success ? 200 : 422);
 70→});
 71→
 72→// GET /api/analysis/session/stream?sessionId=X
 73→// SSE endpoint — streams progress events during session analysis.
 74→// onProgress is non-async because analyzeSession calls it without await;
 75→// stream.writeSSE is fire-and-forget for progress events (non-fatal if missed).
 76→app.get('/session/stream', async (c) => {
 77→  if (!isLLMConfigured()) {
 78→    return c.json({
 79→      success: false,
 80→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
 81→    }, 400);
 82→  }
 83→
 84→  const sessionId = c.req.query('sessionId');
 85→  if (!sessionId) {
 86→    return c.json({ error: 'Missing required query param: sessionId' }, 400);
 87→  }
 88→
 89→  const db = getDb();
 90→
 91→  const session = db.prepare(`
 92→    SELECT id, project_id, project_name, project_path, summary, ended_at
 93→    FROM sessions WHERE id = ?
 94→  `).get(sessionId) as SessionData | undefined;
 95→
 96→  if (!session) {
 97→    return c.json({ error: 'Session not found' }, 404);
 98→  }
 99→
100→  const messages = db.prepare(`
101→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
102→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
103→  `).all(sessionId) as SQLiteMessageRow[];
104→
105→  const llmConfig = loadLLMConfig();
106→  return streamSSE(c, async (stream) => {
107→    const streamStart = Date.now();
108→    try {
109→      const abortSignal = c.req.raw.signal;
110→
111→      await stream.writeSSE({
112→        event: 'progress',
113→        data: JSON.stringify({ phase: 'loading_messages', message: 'Loading messages...' }),
114→      });
115→
116→      const result = await analyzeSession(session, messages, {
117→        signal: abortSignal,
118→        onProgress: (progress) => {
119→          const message = progress.phase === 'saving'
120→            ? 'Saving insights...'
121→            : progress.currentChunk && progress.totalChunks
122→              ? `Analyzing... (${progress.currentChunk} of ${progress.totalChunks})`
123→              : 'Analyzing...';
124→          void stream.writeSSE({
125→            event: 'progress',
126→            data: JSON.stringify({ ...progress, message }),
127→          }).catch(() => {});
128→        },
129→      });
130→
131→      const streamBaseProperties = {
132→        type: 'session',
133→        llm_provider: llmConfig?.provider,
134→        llm_model: llmConfig?.model,
135→        duration_ms: Date.now() - streamStart,
136→        success: result.success,
137→      };
138→      if (!result.success) {
139→        const streamErrorProperties = {
140→          ...streamBaseProperties,
141→          error_type: result.error_type,
142→          error_message: result.error,
143→        };
144→        trackEvent('analysis_run', streamErrorProperties);
145→        captureError(new Error(result.error ?? 'analysis_run stream failed'), streamErrorProperties);
146→        await stream.writeSSE({
147→          event: 'error',
148→          data: JSON.stringify({ error: result.error ?? 'Analysis failed' }),
149→        });
150→      } else {
151→        trackEvent('analysis_run', streamBaseProperties);
152→        trackEvent('insight_generated', {
153→          type: 'session',
154→          count: result.insights.length,
155→        });
156→        const summaryInsight = result.insights.find(i => i.type === 'summary');
157→        await stream.writeSSE({
158→          event: 'complete',
159→          data: JSON.stringify({
160→            success: true,
161→            insightCount: result.insights.length,
162→            tokenUsage: result.usage,
163→            suggestedTitle: summaryInsight?.title ?? null,
164→          }),
165→        });
166→      }
167→    } catch (err) {
168→      const message = err instanceof Error ? err.message : 'Unknown error';
169→      captureError(err, { type: 'session_stream', llm_provider: llmConfig?.provider, llm_model: llmConfig?.model });
170→      await stream.writeSSE({
171→        event: 'error',
172→        data: JSON.stringify({ error: message }),
173→      }).catch(() => {});
174→    }
175→  });
176→});
177→
178→// POST /api/analysis/prompt-quality
179→// Body: { sessionId: string }
180→// Runs prompt quality analysis on user messages in the session.
181→app.post('/prompt-quality', async (c) => {
182→  if (!isLLMConfigured()) {
183→    return c.json({
184→      success: false,
185→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
186→    }, 400);
187→  }
188→
189→  const body = await c.req.json<{ sessionId?: string }>();
190→  if (!body.sessionId || typeof body.sessionId !== 'string') {
191→    return c.json({ error: 'Missing required field: sessionId' }, 400);
192→  }
193→
194→  const db = getDb();
195→
196→  const session = db.prepare(`
197→    SELECT id, project_id, project_name, project_path, summary, ended_at
198→    FROM sessions WHERE id = ?
