238→// GET /api/analysis/prompt-quality/stream?sessionId=X
239→// SSE endpoint — streams progress events during prompt quality analysis.
240→// onProgress is non-async because analyzePromptQuality calls it without await;
241→// stream.writeSSE is fire-and-forget for progress events (non-fatal if missed).
242→app.get('/prompt-quality/stream', async (c) => {
243→  if (!isLLMConfigured()) {
244→    return c.json({
245→      success: false,
246→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
247→    }, 400);
248→  }
249→
250→  const sessionId = c.req.query('sessionId');
251→  if (!sessionId) {
252→    return c.json({ error: 'Missing required query param: sessionId' }, 400);
253→  }
254→
255→  const db = getDb();
256→
257→  const session = db.prepare(`
258→    SELECT id, project_id, project_name, project_path, summary, ended_at
259→    FROM sessions WHERE id = ?
260→  `).get(sessionId) as SessionData | undefined;
261→
262→  if (!session) {
263→    return c.json({ error: 'Session not found' }, 404);
264→  }
265→
266→  const messages = db.prepare(`
267→    SELECT id, session_id, type, content, thinking, tool_calls, tool_results, usage, timestamp, parent_id
268→    FROM messages WHERE session_id = ? ORDER BY timestamp ASC
269→  `).all(sessionId) as SQLiteMessageRow[];
270→
271→  const llmConfig = loadLLMConfig();
272→  return streamSSE(c, async (stream) => {
273→    const pqStreamStart = Date.now();
274→    try {
275→      const abortSignal = c.req.raw.signal;
276→
277→      await stream.writeSSE({
278→        event: 'progress',
279→        data: JSON.stringify({ phase: 'loading_messages', message: 'Loading messages...' }),
280→      });
281→
282→      const result = await analyzePromptQuality(session, messages, {
283→        signal: abortSignal,
284→        onProgress: (progress) => {
285→          const message = progress.phase === 'saving'
286→            ? 'Saving insights...'
287→            : 'Analyzing prompt quality...';
288→          void stream.writeSSE({
289→            event: 'progress',
290→            data: JSON.stringify({ ...progress, message }),
291→          }).catch(() => {});
292→        },
293→      });
294→
295→      const pqStreamBaseProperties = {
296→        type: 'prompt-quality',
297→        llm_provider: llmConfig?.provider,
298→        llm_model: llmConfig?.model,
299→        duration_ms: Date.now() - pqStreamStart,
300→        success: result.success,
301→      };
302→      if (!result.success) {
303→        const pqStreamErrorProperties = {
304→          ...pqStreamBaseProperties,
305→          error_type: result.error_type,
306→          error_message: result.error,
307→        };
308→        trackEvent('analysis_run', pqStreamErrorProperties);
309→        captureError(new Error(result.error ?? 'prompt_quality stream failed'), pqStreamErrorProperties);
310→        await stream.writeSSE({
311→          event: 'error',
312→          data: JSON.stringify({ error: result.error ?? 'Prompt quality analysis failed' }),
313→        });
314→      } else {
315→        trackEvent('analysis_run', pqStreamBaseProperties);
316→        trackEvent('insight_generated', {
317→          type: 'prompt_quality',
318→          count: result.insights.length,
319→        });
320→        await stream.writeSSE({
321→          event: 'complete',
322→          data: JSON.stringify({
323→            success: true,
324→            insightCount: result.insights.length,
325→            tokenUsage: result.usage,
326→            suggestedTitle: null,
327→          }),
328→        });
329→      }
330→    } catch (err) {
331→      const message = err instanceof Error ? err.message : 'Unknown error';
332→      captureError(err, { type: 'prompt_quality_stream', llm_provider: llmConfig?.provider, llm_model: llmConfig?.model });
333→      await stream.writeSSE({
334→        event: 'error',
335→        data: JSON.stringify({ error: message }),
336→      }).catch(() => {});
337→    }
338→  });
339→});
