  1→// Core analysis engine — server-side.
  2→// Ported from web repo (src/lib/llm/analysis.ts) with SQLite persistence replacing Firestore.
  3→// Key differences from web repo:
  4→//   - Uses SQLiteMessageRow instead of web Message type
  5→//   - Writes insights directly to SQLite via getDb() (not Firestore)
  6→//   - Abort handling uses error.name === 'AbortError' (not DOMException)
  7→//   - Uses session's existing project_id from SQLite (not re-derived hash)
  8→
  9→import { randomUUID } from 'crypto';
 10→import { getDb } from '@code-insights/cli/db/client';
 11→import { createLLMClient, isLLMConfigured } from './client.js';
 12→import {
 13→  SESSION_ANALYSIS_SYSTEM_PROMPT,
 14→  generateSessionAnalysisPrompt,
 15→  formatMessagesForAnalysis,
 16→  parseAnalysisResponse,
 17→  PROMPT_QUALITY_SYSTEM_PROMPT,
 18→  generatePromptQualityPrompt,
 19→  parsePromptQualityResponse,
 20→  type SQLiteMessageRow,
 21→  type AnalysisResponse,
 22→  type PromptQualityResponse,
 23→  type ParseError,
 24→} from './prompts.js';
 25→
 26→// Re-export SQLiteMessageRow so routes can import it from analysis.ts directly
 27→export type { SQLiteMessageRow };
 28→
 29→// Maximum tokens to send to LLM (leaving room for response)
 30→const MAX_INPUT_TOKENS = 80000;
 31→const ANALYSIS_VERSION = '2.0.0';
 32→
 33→export interface AnalysisProgress {
 34→  phase: 'loading_messages' | 'analyzing' | 'saving';
 35→  currentChunk?: number;
 36→  totalChunks?: number;
 37→}
 38→
 39→export interface AnalysisOptions {
 40→  onProgress?: (progress: AnalysisProgress) => void;
 41→  signal?: AbortSignal;
 42→}
 43→
 44→export interface AnalysisResult {
 45→  success: boolean;
 46→  insights: InsightRow[];
 47→  error?: string;
 48→  error_type?: string;
 49→  response_length?: number;
 50→  usage?: {
 51→    inputTokens: number;
 52→    outputTokens: number;
 53→  };
 54→}
 55→
 56→// Re-export ParseError so routes can import it from analysis.ts
 57→export type { ParseError };
 58→
 59→// Shape of a saved insight row (matches the SQLite schema)
 60→export interface InsightRow {
 61→  id: string;
 62→  session_id: string;
 63→  project_id: string;
 64→  project_name: string;
 65→  type: string;
 66→  title: string;
 67→  content: string;
 68→  summary: string;
 69→  bullets: string;           // JSON-encoded string[]
 70→  confidence: number;
 71→  source: 'llm';
 72→  metadata: string | null;   // JSON-encoded object
 73→  timestamp: string;         // ISO 8601
 74→  created_at: string;        // ISO 8601
 75→  scope: string;
 76→  analysis_version: string;
 77→}
 78→
 79→// Minimal session data needed for analysis (from SQLite sessions row)
 80→export interface SessionData {
 81→  id: string;
 82→  project_id: string;
 83→  project_name: string;
 84→  project_path: string;
 85→  summary: string | null;
 86→  ended_at: string;          // ISO 8601
 87→}
 88→
 89→/**
 90→ * Analyze a session and generate insights, saving them to SQLite.
 91→ */
 92→export async function analyzeSession(
 93→  session: SessionData,
 94→  messages: SQLiteMessageRow[],
 95→  options?: AnalysisOptions
 96→): Promise<AnalysisResult> {
 97→  if (!isLLMConfigured()) {
 98→    return {
 99→      success: false,
100→      insights: [],
101→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
102→    };
103→  }
104→
105→  if (messages.length === 0) {
106→    return {
107→      success: false,
108→      insights: [],
109→      error: 'No messages found for this session.',
110→    };
111→  }
112→
113→  try {
114→    const client = createLLMClient();
115→    const formattedMessages = formatMessagesForAnalysis(messages);
116→    const estimatedTokens = client.estimateTokens(formattedMessages);
117→
118→    let analysisResponse: AnalysisResponse;
119→    let totalInputTokens = 0;
120→    let totalOutputTokens = 0;
121→
122→    if (estimatedTokens > MAX_INPUT_TOKENS) {
123→      // Chunk the messages and analyze separately
124→      const chunks = chunkMessages(messages, client.estimateTokens.bind(client));
125→      const chunkResponses: AnalysisResponse[] = [];
126→      const totalChunks = chunks.length;
127→
128→      for (let i = 0; i < chunks.length; i++) {
129→        const chunk = chunks[i];
130→        options?.onProgress?.({ phase: 'analyzing', currentChunk: i + 1, totalChunks });
131→
132→        const chunkFormatted = formatMessagesForAnalysis(chunk);
133→        const prompt = generateSessionAnalysisPrompt(
134→          session.project_name,
135→          session.summary,
136→          chunkFormatted
137→        );
138→
139→        const response = await client.chat([
140→          { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
141→          { role: 'user', content: prompt },
142→        ], { signal: options?.signal });
143→
144→        if (response.usage) {
145→          totalInputTokens += response.usage.inputTokens;
146→          totalOutputTokens += response.usage.outputTokens;
147→        }
148→
149→        const parsed = parseAnalysisResponse(response.content);
150→        if (parsed.success) chunkResponses.push(parsed.data);
151→      }
152→
153→      if (chunkResponses.length === 0) {
154→        return {
155→          success: false,
156→          insights: [],
157→          error: 'All chunks failed to parse LLM response',
158→          error_type: 'json_parse_error',
159→          usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
160→        };
161→      }
162→
163→      analysisResponse = mergeAnalysisResponses(chunkResponses);
164→    } else {
165→      options?.onProgress?.({ phase: 'analyzing', currentChunk: 1, totalChunks: 1 });
166→      const prompt = generateSessionAnalysisPrompt(
167→        session.project_name,
168→        session.summary,
169→        formattedMessages
170→      );
171→
172→      const response = await client.chat([
173→        { role: 'system', content: SESSION_ANALYSIS_SYSTEM_PROMPT },
174→        { role: 'user', content: prompt },
175→      ], { signal: options?.signal });
176→
177→      if (response.usage) {
178→        totalInputTokens = response.usage.inputTokens;
179→        totalOutputTokens = response.usage.outputTokens;
180→      }
181→
182→      const parsed = parseAnalysisResponse(response.content);
183→      if (!parsed.success) {
184→        return {
185→          success: false,
186→          insights: [],
187→          error: 'Failed to parse LLM response. Please try again.',
188→          error_type: parsed.error.error_type,
189→          response_length: parsed.error.response_length,
190→        };
191→      }
192→
193→      analysisResponse = parsed.data;
194→    }
195→
196→    options?.onProgress?.({ phase: 'saving' });
197→    const insights = convertToInsightRows(analysisResponse, session);
198→
199→    // Save new insights first, then delete old non-prompt-quality insights
200→    // (safe order: if save fails, old data is preserved)
201→    saveInsightsToDb(insights);
202→    deleteSessionInsights(session.id, {
203→      excludeTypes: ['prompt_quality'],
204→      excludeIds: insights.map(i => i.id),
205→    });
206→
207→    return {
208→      success: true,
209→      insights,
210→      usage: { inputTokens: totalInputTokens, outputTokens: totalOutputTokens },
211→    };
212→  } catch (error) {
213→    if (error instanceof Error && error.name === 'AbortError') {
214→      return { success: false, insights: [], error: 'Analysis cancelled', error_type: 'abort' };
215→    }
216→    return {
217→      success: false,
218→      insights: [],
219→      error: error instanceof Error ? error.message : 'Analysis failed',
220→      error_type: 'api_error',
221→    };
222→  }
223→}
