477→// --- Internal helpers ---
478→
479→function chunkMessages(
480→  messages: SQLiteMessageRow[],
481→  estimateTokens: (text: string) => number
482→): SQLiteMessageRow[][] {
483→  const chunks: SQLiteMessageRow[][] = [];
484→  let currentChunk: SQLiteMessageRow[] = [];
485→  let currentTokens = 0;
486→  const chunkLimit = MAX_INPUT_TOKENS * 0.8;
487→
488→  for (const message of messages) {
489→    let toolResults: Array<{ output?: string }> = [];
490→    try {
491→      toolResults = message.tool_results ? JSON.parse(message.tool_results) as Array<{ output?: string }> : [];
492→    } catch {
493→      toolResults = [];
494→    }
495→
496→    const messageText = [
497→      message.content,
498→      message.thinking?.slice(0, 1000) ?? '',
499→      ...toolResults.map(r => (r.output || '').slice(0, 200)),
500→    ].join(' ');
501→    const messageTokens = estimateTokens(messageText);
502→
503→    if (currentTokens + messageTokens > chunkLimit && currentChunk.length > 0) {
504→      chunks.push(currentChunk);
505→      currentChunk = [];
506→      currentTokens = 0;
507→    }
508→
509→    currentChunk.push(message);
510→    currentTokens += messageTokens;
511→  }
512→
513→  if (currentChunk.length > 0) {
514→    chunks.push(currentChunk);
515→  }
516→
517→  return chunks;
518→}
519→
520→function mergeAnalysisResponses(responses: AnalysisResponse[]): AnalysisResponse {
521→  if (responses.length === 0) {
522→    return {
523→      summary: { title: 'Analysis failed', content: '', bullets: [] },
524→      decisions: [],
525→      learnings: [],
526→    };
527→  }
528→
529→  if (responses.length === 1) return responses[0];
530→
531→  const merged: AnalysisResponse = {
532→    summary: responses[0].summary,
533→    decisions: [],
534→    learnings: [],
535→  };
536→
537→  for (const response of responses) {
538→    merged.decisions.push(...response.decisions);
539→    merged.learnings.push(...response.learnings);
540→  }
541→
542→  merged.decisions = deduplicateByTitle(merged.decisions).slice(0, 3);
543→  merged.learnings = deduplicateByTitle(merged.learnings).slice(0, 5);
544→
545→  return merged;
546→}
547→
548→function deduplicateByTitle<T extends { title: string }>(items: T[]): T[] {
549→  const seen = new Set<string>();
550→  return items.filter((item) => {
551→    const normalized = item.title.toLowerCase().trim();
552→    if (seen.has(normalized)) return false;
553→    seen.add(normalized);
554→    return true;
555→  });
556→}
557→
558→function convertToInsightRows(response: AnalysisResponse, session: SessionData): InsightRow[] {
559→  const insights: InsightRow[] = [];
560→  const now = new Date().toISOString();
561→
562→  insights.push({
563→    id: randomUUID(),
564→    session_id: session.id,
565→    project_id: session.project_id,
566→    project_name: session.project_name,
567→    type: 'summary',
568→    title: response.summary.title,
569→    content: response.summary.content,
570→    summary: response.summary.content,
571→    bullets: JSON.stringify(response.summary.bullets),
572→    confidence: 0.9,
573→    source: 'llm',
574→    metadata: null,
575→    timestamp: session.ended_at,
576→    created_at: now,
577→    scope: 'session',
578→    analysis_version: ANALYSIS_VERSION,
579→  });
580→
581→  for (const decision of response.decisions) {
582→    const confidence = decision.confidence ?? 85;
583→    if (confidence < 70) continue;
584→
585→    insights.push({
586→      id: randomUUID(),
587→      session_id: session.id,
588→      project_id: session.project_id,
589→      project_name: session.project_name,
590→      type: 'decision',
591→      title: decision.title,
592→      content: decision.content,
593→      summary: decision.content.slice(0, 200),
594→      bullets: JSON.stringify(decision.alternatives || []),
595→      confidence: confidence / 100,
596→      source: 'llm',
597→      metadata: JSON.stringify({
598→        reasoning: decision.reasoning,
599→        alternatives: decision.alternatives,
600→        evidence: decision.evidence,
601→      }),
602→      timestamp: session.ended_at,
603→      created_at: now,
604→      scope: 'session',
605→      analysis_version: ANALYSIS_VERSION,
606→    });
607→  }
608→
609→  for (const learning of response.learnings) {
610→    const confidence = learning.confidence ?? 80;
611→    if (confidence < 70) continue;
612→
613→    insights.push({
614→      id: randomUUID(),
615→      session_id: session.id,
616→      project_id: session.project_id,
617→      project_name: session.project_name,
618→      type: 'learning',
619→      title: learning.title,
620→      content: learning.content,
621→      summary: learning.content.slice(0, 200),
622→      bullets: JSON.stringify([]),
623→      confidence: confidence / 100,
624→      source: 'llm',
625→      metadata: JSON.stringify({
626→        context: learning.context,
627→        evidence: learning.evidence,
628→      }),
629→      timestamp: session.ended_at,
630→      created_at: now,
631→      scope: 'session',
632→      analysis_version: ANALYSIS_VERSION,
633→    });
634→  }
635→
636→  return insights;
637→}
638→
639→function convertPromptQualityToInsightRow(response: PromptQualityResponse, session: SessionData): InsightRow {
640→  const now = new Date().toISOString();
641→
642→  return {
643→    id: randomUUID(),
644→    session_id: session.id,
645→    project_id: session.project_id,
646→    project_name: session.project_name,
647→    type: 'prompt_quality',
648→    title: `Prompt Efficiency: ${response.efficiencyScore}/100`,
649→    content: response.overallAssessment,
650→    summary: response.overallAssessment,
651→    bullets: JSON.stringify(response.tips),
652→    confidence: 0.85,
653→    source: 'llm',
654→    metadata: JSON.stringify({
655→      efficiencyScore: response.efficiencyScore,
656→      wastedTurns: response.wastedTurns,
657→      antiPatterns: response.antiPatterns,
658→      potentialMessageReduction: response.potentialMessageReduction,
659→    }),
660→    timestamp: session.ended_at,
661→    created_at: now,
662→    scope: 'session',
663→    analysis_version: ANALYSIS_VERSION,
664→  };
665→}
666→
667→/**
668→ * Write insight rows to SQLite using prepared statements.
669→ */
670→function saveInsightsToDb(insights: InsightRow[]): void {
671→  const db = getDb();
672→  const insert = db.prepare(`
673→    INSERT OR REPLACE INTO insights (
674→      id, session_id, project_id, project_name, type, title, content,
675→      summary, bullets, confidence, source, metadata, timestamp,
676→      created_at, scope, analysis_version
677→    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
678→  `);
679→
680→  const insertMany = db.transaction((rows: InsightRow[]) => {
681→    for (const row of rows) {
682→      insert.run(
683→        row.id,
684→        row.session_id,
685→        row.project_id,
686→        row.project_name,
687→        row.type,
688→        row.title,
689→        row.content,
690→        row.summary,
691→        row.bullets,
692→        row.confidence,
693→        row.source,
694→        row.metadata,
695→        row.timestamp,
696→        row.created_at,
697→        row.scope,
698→        row.analysis_version,
699→      );
700→    }
701→  });
702→
703→  insertMany(insights);
704→}
