  1→// HTTP client for the Hono API server.
  2→// Base URL is relative in production (SPA served by the same server).
  3→// In Vite dev mode, the proxy forwards /api -> localhost:7890.
  4→
  5→import type { Project, Session, Message, Insight, DashboardStats, LLMConfig } from '@/lib/types';
  6→
  7→const BASE = '/api';
  8→
  9→async function request<T>(path: string, init?: RequestInit): Promise<T> {
 10→  // Only set Content-Type when a body is present — setting it on GET requests
 11→  // adds unnecessary headers and can confuse some intermediaries.
 12→  const headers: Record<string, string> = { ...(init?.headers as Record<string, string>) };
 13→  if (init?.body) {
 14→    headers['Content-Type'] = 'application/json';
 15→  }
 16→  const res = await fetch(`${BASE}${path}`, { ...init, headers });
 17→  if (!res.ok) {
 18→    const text = await res.text().catch(() => res.statusText);
 19→    throw new Error(`API ${res.status}: ${text}`);
 20→  }
 21→  return res.json() as Promise<T>;
 22→}
