 27→  const { data: projects = [], isLoading: projectsLoading, isError: projectsError, refetch: refetchProjects } = useProjects();
 28→  const { tooltipBg, tooltipBorder } = useThemeColors();
 29→
 30→  const loading = sessionsLoading || insightsLoading || projectsLoading;
 31→
 32→  // Build daily stats from sessions
 33→  const dailyStats: DailyStats[] = useMemo(() => {
 34→    const grouped: Record<string, { session_count: number; insight_count: number }> = {};
 35→    for (const s of sessions) {
 36→      const date = s.started_at.slice(0, 10);
 37→      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
 38→      grouped[date].session_count++;
 39→    }
 40→    for (const i of insights) {
 41→      const date = i.timestamp.slice(0, 10);
 42→      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
 43→      grouped[date].insight_count++;
 44→    }
 45→    return Object.entries(grouped)
 46→      .sort(([a], [b]) => a.localeCompare(b))
 47→      .map(([date, counts]) => ({
 48→        date,
 49→        session_count: counts.session_count,
 50→        message_count: 0,
 51→        insight_count: counts.insight_count,
 52→      }));
 53→  }, [sessions, insights]);
 54→
 55→  // Insight type breakdown
 56→  const insightsByType = useMemo(() => ({
 57→    summary: insights.filter((i) => i.type === 'summary').length,
 58→    decision: insights.filter((i) => i.type === 'decision').length,
 59→    learning: insights.filter((i) => i.type === 'learning' || i.type === 'technique').length,
 60→    prompt_quality: insights.filter((i) => i.type === 'prompt_quality').length,
 61→  }), [insights]);
 62→
 63→  // Project stats
 64→  const projectStats = useMemo(() => {
 65→    const statsMap: Record<
 66→      string,
 67→      {
 68→        projectId: string;
 69→        projectName: string;
 70→        sessionCount: number;
 71→        insightCounts: { summary: number; decision: number; learning: number; prompt_quality: number };
 72→        totalInputTokens: number;
 73→        totalOutputTokens: number;
 74→        estimatedCostUsd: number;
 75→      }
 76→    > = {};
 77→
 78→    for (const s of sessions) {
 79→      if (!statsMap[s.project_id]) {
 80→        statsMap[s.project_id] = {
 81→          projectId: s.project_id,
 82→          projectName: s.project_name,
 83→          sessionCount: 0,
 84→          insightCounts: { summary: 0, decision: 0, learning: 0, prompt_quality: 0 },
 85→          totalInputTokens: 0,
 86→          totalOutputTokens: 0,
 87→          estimatedCostUsd: 0,
 88→        };
 89→      }
 90→      statsMap[s.project_id].sessionCount++;
 91→      statsMap[s.project_id].totalInputTokens += s.total_input_tokens ?? 0;
 92→      statsMap[s.project_id].totalOutputTokens += s.total_output_tokens ?? 0;
 93→      statsMap[s.project_id].estimatedCostUsd += s.estimated_cost_usd ?? 0;
 94→    }
 95→
 96→    for (const i of insights) {
 97→      if (statsMap[i.project_id]) {
 98→        const type = i.type === 'technique' ? 'learning' : i.type;
 99→        if (type in statsMap[i.project_id].insightCounts) {
100→          statsMap[i.project_id].insightCounts[type as keyof typeof statsMap[string]['insightCounts']]++;
101→        }
102→      }
103→    }
104→
105→    return Object.values(statsMap).sort((a, b) => b.sessionCount - a.sessionCount);
106→  }, [sessions, insights]);
107→
108→  // Model distribution
109→  const modelDistribution = useMemo(() => {
110→    const dist: Record<string, number> = {};
111→    for (const s of sessions) {
112→      if (s.primary_model) {
113→        dist[s.primary_model] = (dist[s.primary_model] ?? 0) + 1;
114→      }
115→    }
116→    return dist;
117→  }, [sessions]);
118→
119→  const totalSessions = sessions.length;
120→  const totalInsights = insights.length;
121→  const totalCost = sessions.reduce((sum, s) => sum + (s.estimated_cost_usd ?? 0), 0);
122→  const totalTokens = sessions.reduce(
123→    (sum, s) =>
124→      sum +
125→      (s.total_input_tokens ?? 0) +
126→      (s.total_output_tokens ?? 0) +
127→      (s.cache_creation_tokens ?? 0) +
128→      (s.cache_read_tokens ?? 0),
129→    0
130→  );
131→
132→  // Top projects chart data
133→  const projectChartData = projectStats
134→    .slice(0, 10)
135→    .map((p) => ({
136→      name: p.projectName.length > 15 ? p.projectName.slice(0, 15) + '...' : p.projectName,
137→      sessions: p.sessionCount,
138→    }));
139→
140→  const hasError = sessionsError || insightsError || projectsError;
141→
142→  if (hasError && !loading) {
143→    const retryAll = () => {
144→      if (sessionsError) refetchSessions();
145→      if (insightsError) refetchInsights();
146→      if (projectsError) refetchProjects();
147→    };
148→    return (
149→      <div className="p-6 space-y-6">
150→        <div>
151→          <h1 className="text-2xl font-bold">Analytics</h1>
152→          <p className="text-muted-foreground">Visualize your AI coding usage patterns</p>
153→        </div>
154→        <ErrorCard message="Failed to load analytics data" onRetry={retryAll} />
155→      </div>
156→    );
157→  }
158→
159→  if (loading) {
160→    return (
161→      <div className="p-6 space-y-6">
162→        <div>
163→          <h1 className="text-2xl font-bold">Analytics</h1>
164→          <p className="text-muted-foreground">Visualize your AI coding usage patterns</p>
165→        </div>
166→        <div className="grid gap-4 md:grid-cols-4">
167→          {[...Array(4)].map((_, i) => (
168→            <Card key={i}>
169→              <CardHeader className="pb-2">
170→                <Skeleton className="h-4 w-24" />
171→              </CardHeader>
172→              <CardContent>
173→                <Skeleton className="h-8 w-16" />
174→              </CardContent>
175→            </Card>
176→          ))}
177→        </div>
178→        <Skeleton className="h-[300px] w-full rounded-lg" />
179→      </div>
180→    );
181→  }
182→
183→  return (
184→    <div className="p-6 space-y-6">
185→      <div>
186→        <h1 className="text-2xl font-bold">Analytics</h1>
187→        <p className="text-muted-foreground">Visualize your AI coding usage patterns</p>
188→      </div>
189→
190→      {/* Summary Stats */}
191→      <div className="grid gap-4 md:grid-cols-4">
192→        <Card>
193→          <CardHeader className="pb-2">
194→            <CardTitle className="text-sm font-medium">Total Sessions</CardTitle>
195→          </CardHeader>
196→          <CardContent>
197→            <div className="text-3xl font-bold">{totalSessions}</div>
198→          </CardContent>
199→        </Card>
200→
201→        <Card>
202→          <CardHeader className="pb-2">
203→            <CardTitle className="text-sm font-medium">Total Insights</CardTitle>
204→          </CardHeader>
205→          <CardContent>
206→            <div className="text-3xl font-bold">{totalInsights}</div>
207→          </CardContent>
208→        </Card>
209→
210→        <Card>
211→          <CardHeader className="pb-2">
212→            <CardTitle className="text-sm font-medium">Active Projects</CardTitle>
213→          </CardHeader>
214→          <CardContent>
215→            <div className="text-3xl font-bold">{projects.length}</div>
216→          </CardContent>
217→        </Card>
218→
219→        <Card>
220→          <CardHeader className="pb-2">
221→            <CardTitle className="text-sm font-medium">
222→              {totalCost > 0 ? 'Estimated Cost' : 'Total Tokens'}
223→            </CardTitle>
224→          </CardHeader>
225→          <CardContent>
226→            <div className="text-3xl font-bold">
227→              {totalCost > 0
228→                ? `$${totalCost.toFixed(2)}`
229→                : totalTokens > 0
230→                  ? formatTokenCount(totalTokens)
231→                  : '—'}
232→            </div>
233→          </CardContent>
234→        </Card>
235→      </div>
236→
237→      {/* Activity Over Time */}
238→      <ActivityChart data={dailyStats} />
239→
240→      {/* Charts Row */}
241→      <div className="grid gap-6 md:grid-cols-2">
242→        <InsightTypeChart data={insightsByType} />
243→
244→        {/* Sessions by Project */}
245→        <Card>
246→          <CardHeader>
247→            <CardTitle className="text-base">Top Projects</CardTitle>
248→          </CardHeader>
249→          <CardContent>
250→            <div className="h-[200px]">
251→              {projectChartData.length > 0 ? (
252→                <ResponsiveContainer width="100%" height="100%">
253→                  <BarChart data={projectChartData} layout="vertical">
254→                    <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
255→                    <XAxis type="number" tick={{ fontSize: 12 }} />
256→                    <YAxis
257→                      type="category"
258→                      dataKey="name"
259→                      tick={{ fontSize: 11 }}
260→                      width={100}
261→                    />
262→                    <Tooltip
263→                      contentStyle={{
264→                        backgroundColor: tooltipBg,
265→                        borderColor: tooltipBorder,
266→                        borderRadius: '8px',
