269→                    />
270→                    <Bar
271→                      dataKey="sessions"
272→                      fill={CHART_COLORS.projects.sessions}
273→                      name="Sessions"
274→                    />
275→                  </BarChart>
276→                </ResponsiveContainer>
277→              ) : (
278→                <div className="flex h-full items-center justify-center">
279→                  <p className="text-sm text-muted-foreground">No project data yet</p>
280→                </div>
