282→            </div>
283→          </CardContent>
284→        </Card>
285→      </div>
286→
287→      {/* Model Distribution */}
288→      {Object.keys(modelDistribution).length > 0 && (
289→        <Card>
290→          <CardHeader>
291→            <CardTitle className="text-base">Model Distribution</CardTitle>
292→          </CardHeader>
293→          <CardContent>
294→            <div className="space-y-2">
295→              {Object.entries(modelDistribution)
296→                .sort(([, a], [, b]) => b - a)
297→                .map(([model, count], i) => (
298→                  <div key={model} className="flex items-center gap-3">
299→                    <div
300→                      className="h-3 w-3 rounded-full shrink-0"
301→                      style={{
302→                        backgroundColor:
303→                          CHART_COLORS.models[i % CHART_COLORS.models.length],
