311→                        : '—'}
312→                    </span>
313→                  </div>
314→                ))}
315→            </div>
316→          </CardContent>
317→        </Card>
318→      )}
319→
320→      {/* Project Table */}
321→      <Card>
322→        <CardHeader>
323→          <CardTitle className="text-base">All Projects</CardTitle>
324→        </CardHeader>
325→        <CardContent>
326→          <div className="overflow-x-auto">
327→            <table className="w-full text-sm">
