330→                  <th className="py-3 text-left font-medium">Project</th>
331→                  <th className="py-3 text-right font-medium">Sessions</th>
332→                  <th className="py-3 text-right font-medium">Summaries</th>
333→                  <th className="py-3 text-right font-medium">Decisions</th>
334→                  <th className="py-3 text-right font-medium">Learnings</th>
335→                  <th className="py-3 text-right font-medium">Est. Cost</th>
336→                  <th className="py-3 text-right font-medium">Tokens</th>
337→                </tr>
338→              </thead>
339→              <tbody>
340→                {projectStats.map((project) => {
341→                  const tokens =
342→                    project.totalInputTokens + project.totalOutputTokens;
343→                  return (
344→                    <tr key={project.projectId} className="border-b last:border-0">
345→                      <td className="py-3">{project.projectName}</td>
346→                      <td className="py-3 text-right">{project.sessionCount}</td>
347→                      <td className="py-3 text-right">{project.insightCounts.summary}</td>
348→                      <td className="py-3 text-right">{project.insightCounts.decision}</td>
349→                      <td className="py-3 text-right">{project.insightCounts.learning}</td>
350→                      <td className="py-3 text-right">
351→                        {project.estimatedCostUsd > 0
352→                          ? `$${project.estimatedCostUsd.toFixed(2)}`
353→                          : '—'}
354→                      </td>
355→                      <td className="py-3 text-right">
