  1→// Dashboard-specific types matching the Hono API response format.
  2→// The server returns SQLite rows as-is — snake_case keys, ISO 8601 date strings.
  3→// Convert to Date objects only at the component boundary when needed.
  4→
  5→export interface Project {
  6→  id: string;
  7→  name: string;
  8→  path: string;
  9→  git_remote_url: string | null;
 10→  session_count: number;
 11→  last_activity: string;        // ISO 8601
 12→  created_at: string;           // ISO 8601
 13→  updated_at: string;           // ISO 8601
 14→  total_input_tokens?: number;
 15→  total_output_tokens?: number;
 16→  cache_creation_tokens?: number;
 17→  cache_read_tokens?: number;
 18→  estimated_cost_usd?: number;
 19→}
 20→
 21→export type SessionCharacter =
 22→  | 'deep_focus'
 23→  | 'bug_hunt'
 24→  | 'feature_build'
 25→  | 'exploration'
 26→  | 'refactor'
 27→  | 'learning'
 28→  | 'quick_task';
 29→
 30→export type TitleSource = 'claude' | 'user_message' | 'insight' | 'character' | 'fallback';
 31→
 32→export interface Session {
 33→  id: string;
 34→  project_id: string;
 35→  project_name: string;
 36→  project_path: string;
 37→  git_remote_url: string | null;
 38→  summary: string | null;
 39→  custom_title: string | null;
 40→  generated_title: string | null;
 41→  title_source: TitleSource | null;
 42→  session_character: SessionCharacter | null;
 43→  started_at: string;           // ISO 8601
 44→  ended_at: string;             // ISO 8601
 45→  message_count: number;
 46→  user_message_count: number;
 47→  assistant_message_count: number;
 48→  tool_call_count: number;
 49→  git_branch: string | null;
 50→  claude_version: string | null;
 51→  source_tool: string | null;
 52→  device_id: string | null;
 53→  device_hostname: string | null;
 54→  device_platform: string | null;
 55→  synced_at: string;            // ISO 8601
 56→  total_input_tokens: number | null;
 57→  total_output_tokens: number | null;
 58→  cache_creation_tokens: number | null;
 59→  cache_read_tokens: number | null;
 60→  estimated_cost_usd: number | null;
 61→  models_used: string | null;   // JSON-encoded string array from SQLite
 62→  primary_model: string | null;
 63→  usage_source: string | null;
 64→}
