 66→export type InsightType = 'summary' | 'decision' | 'learning' | 'technique' | 'prompt_quality';
 67→export type InsightScope = 'session' | 'project' | 'overall';
 68→
 69→export interface Insight {
 70→  id: string;
 71→  session_id: string;
 72→  project_id: string;
 73→  project_name: string;
 74→  type: InsightType;
 75→  title: string;
 76→  content: string;
 77→  summary: string;
 78→  bullets: string;              // JSON-encoded string array from SQLite
 79→  confidence: number;
 80→  source: 'llm';
 81→  metadata: string;             // JSON-encoded object from SQLite
 82→  timestamp: string;            // ISO 8601
 83→  created_at: string;           // ISO 8601
 84→  scope: InsightScope;
 85→  analysis_version: string;
 86→  linked_insight_ids: string | null;
 87→}
