123→/**
124→ * Safely parse a JSON string field from the API.
125→ * Returns defaultValue if the field is null, empty, or invalid JSON.
126→ */
127→export function parseJsonField<T>(value: string | null | undefined, defaultValue: T): T {
128→  if (!value) return defaultValue;
129→  try {
130→    return JSON.parse(value) as T;
131→  } catch {
132→    return defaultValue;
133→  }
134→}
