11→export function useSessions(filters?: SessionFilters) {
12→  return useQuery({
13→    queryKey: ['sessions', filters],
14→    queryFn: () => fetchSessions(filters).then((r) => r.sessions),
15→    refetchInterval: 60_000,
16→  });
17→}
