29→  return useMutation({
30→    mutationFn: ({ id, customTitle }: { id: string; customTitle: string }) =>
31→      patchSession(id, { customTitle }),
32→    onSuccess: (_data, variables) => {
33→      queryClient.invalidateQueries({ queryKey: ['session', variables.id] });
34→      queryClient.invalidateQueries({ queryKey: ['sessions'] });
35→    },
36→  });
37→}
