    const grouped: Record<string, { session_count: number; insight_count: number }> = {};
    for (const s of sessions) {
      if (new Date(s.started_at).getTime() < cutoff) continue;
      const date = s.started_at.slice(0, 10);
      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
      grouped[date].session_count++;
    }
    for (const i of insights) {
      if (new Date(i.timestamp).getTime() < cutoff) continue;
      const date = i.timestamp.slice(0, 10);
      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
      grouped[date].insight_count++;
    }
    return Object.entries(grouped)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([date, counts]) => ({
        date,
        session_count: counts.session_count,
        message_count: 0,
        insight_count: counts.insight_count,
      }));
  }, [sessions, insights, range]);

  // Compute stats for hero — all from dashStats (range-filtered)
  const totalTokens = dashStats
    ? (dashStats.total_input_tokens ?? 0) +
      (dashStats.total_output_tokens ?? 0) +
      (dashStats.cache_creation_tokens ?? 0) +
      (dashStats.cache_read_tokens ?? 0)
    : 0;

  const totalCost = dashStats?.estimated_cost_usd ?? 0;

  const tokenBreakdown = dashStats
    ? {
        inputTokens: dashStats.total_input_tokens ?? 0,
        outputTokens: dashStats.total_output_tokens ?? 0,
        cacheCreationTokens: dashStats.cache_creation_tokens ?? 0,
        cacheReadTokens: dashStats.cache_read_tokens ?? 0,
      }
    : undefined;

  return (
    <div className="p-4 lg:p-6 space-y-3">
      {/* Greeting header */}
      <div className="flex items-start justify-between">
        <div>
          <h1 className="text-2xl font-bold">{getGreeting()}.</h1>
          {!loading && (
            <p className="text-muted-foreground text-sm mt-1 animate-in fade-in slide-in-from-bottom-2 duration-300">
              {sessions.length} session{sessions.length !== 1 ? 's' : ''} loaded
              {' '}&middot; {projects.length} project{projects.length !== 1 ? 's' : ''}
            </p>
          )}
        </div>
        <span className="text-sm text-muted-foreground">{todayLabel}</span>
      </div>

      {/* Error state */}
      {hasError && !loading && (
        <ErrorCard
          message="Failed to load dashboard data"
          onRetry={() => { refetchStats(); refetchSessions(); }}
        />
      )}

      {/* All-time stats hero */}
      {loading ? (
        <StatsHeroSkeleton />
      ) : (
        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 delay-75">
          <StatsHero
            totalSessions={dashStats?.session_count ?? sessions.length}
            totalMessages={dashStats?.total_messages ?? 0}
            totalToolCalls={dashStats?.total_tool_calls ?? 0}
            totalDurationMin={dashStats?.total_duration_min ?? 0}
            totalProjects={dashStats?.active_projects ?? projects.length}
            isExact={true}
            totalTokens={totalTokens > 0 ? totalTokens : undefined}
            totalCost={totalCost > 0 ? totalCost : undefined}
            tokenBreakdown={tokenBreakdown}
          />
        </div>
      )}

      {/* Activity chart */}
      {loading ? (
        <Card>
          <CardHeader className="flex flex-row items-center justify-between pb-1">
            <Skeleton className="h-4 w-16" />
            <div className="flex gap-1">
              <Skeleton className="h-7 w-10 rounded" />
              <Skeleton className="h-7 w-10 rounded" />
              <Skeleton className="h-7 w-8 rounded" />
            </div>
          </CardHeader>
          <CardContent>
            <Skeleton className="h-[250px] w-full rounded" />
          </CardContent>
        </Card>
      ) : (
        <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 delay-150">
          <DashboardActivityChart data={dailyStats} range={range} onRangeChange={setRange} />
        </div>
      )}

      {/* Needs Attention banner */}
      {unanalyzedSessions.length > 0 && (
        <Card className="border-amber-500/20 bg-amber-500/5 hover:shadow-md transition-shadow animate-in fade-in slide-in-from-bottom-2 duration-300 delay-75">
          <CardContent className="flex items-center justify-between py-4">
            <div className="flex items-center gap-2">
              <Sparkles className="h-4 w-4 text-amber-600" />
              <div>
                <p className="text-sm font-medium">
                  {unanalyzedSessions.length} session{unanalyzedSessions.length !== 1 ? 's' : ''}{' '}
                  without analysis
                </p>
                <p className="text-xs text-muted-foreground">
                  Generate AI insights to extract learnings and decisions
                </p>
              </div>
            </div>
            <BulkAnalyzeButton sessions={unanalyzedSessions} />
          </CardContent>
        </Card>
      )}

      {/* Unified activity feed */}
      <div
        className={
          loading ? '' : 'animate-in fade-in slide-in-from-bottom-2 duration-300 delay-300'
        }
      >
        <div className="flex items-center justify-between mb-2">
          <h2 className="text-sm font-semibold">Recent Activity</h2>
          <Link
            to="/sessions"
            className="flex items-center gap-1 text-xs text-muted-foreground hover:text-foreground transition-colors"
          >
            View all
            <ArrowRight className="h-3 w-3" />
          </Link>
        </div>
        <Card>
          <CardContent className="px-4 py-2">
            {loading ? (
              <div className="divide-y divide-border">
                {[...Array(4)].map((_, i) => (
                  <div key={i} className="py-2">
                    <div className="flex items-center justify-between gap-2">
                      <div className="flex items-center gap-2 min-w-0">
                        <Skeleton className="h-6 w-6 rounded-md shrink-0" />
                        <Skeleton className="h-4 w-48" />
                        <Skeleton className="h-3.5 w-20" />
                      </div>
                      <Skeleton className="h-3.5 w-16 shrink-0" />
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <ActivityFeed sessions={sessions} insights={insights} limit={7} />
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useMemo } from 'react';
import { useSessions } from '@/hooks/useSessions';
import { useInsights } from '@/hooks/useInsights';
import { useProjects } from '@/hooks/useProjects';
import { ActivityChart } from '@/components/charts/ActivityChart';
import { InsightTypeChart } from '@/components/charts/InsightTypeChart';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { ErrorCard } from '@/components/ErrorCard';
import { formatTokenCount, formatModelName } from '@/lib/utils';
import { CHART_COLORS } from '@/lib/constants/colors';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
} from 'recharts';
import type { DailyStats } from '@/lib/types';
import { useThemeColors } from '@/lib/hooks/useThemeColors';

export default function AnalyticsPage() {
  const { data: sessions = [], isLoading: sessionsLoading, isError: sessionsError, refetch: refetchSessions } = useSessions({ limit: 500 });
  const { data: insights = [], isLoading: insightsLoading, isError: insightsError, refetch: refetchInsights } = useInsights();
  const { data: projects = [], isLoading: projectsLoading, isError: projectsError, refetch: refetchProjects } = useProjects();
  const { tooltipBg, tooltipBorder } = useThemeColors();

  const loading = sessionsLoading || insightsLoading || projectsLoading;

  // Build daily stats from sessions
  const dailyStats: DailyStats[] = useMemo(() => {
    const grouped: Record<string, { session_count: number; insight_count: number }> = {};
    for (const s of sessions) {
      const date = s.started_at.slice(0, 10);
      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
      grouped[date].session_count++;
    }
    for (const i of insights) {
      const date = i.timestamp.slice(0, 10);
      if (!grouped[date]) grouped[date] = { session_count: 0, insight_count: 0 };
      grouped[date].insight_count++;
    }
    return Object.entries(grouped)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([date, counts]) => ({
        date,
        session_count: counts.session_count,
        message_count: 0,
        insight_count: counts.insight_count,
      }));
  }, [sessions, insights]);

  // Insight type breakdown
  const insightsByType = useMemo(() => ({
    summary: insights.filter((i) => i.type === 'summary').length,
    decision: insights.filter((i) => i.type === 'decision').length,
    learning: insights.filter((i) => i.type === 'learning' || i.type === 'technique').length,
    prompt_quality: insights.filter((i) => i.type === 'prompt_quality').length,
  }), [insights]);

  // Project stats
  const projectStats = useMemo(() => {
    const statsMap: Record<
      string,
      {
        projectId: string;
        projectName: string;
        sessionCount: number;
        insightCounts: { summary: number; decision: number; learning: number; prompt_quality: number };
        totalInputTokens: number;
        totalOutputTokens: number;
        estimatedCostUsd: number;
      }
    > = {};

    for (const s of sessions) {
      if (!statsMap[s.project_id]) {
        statsMap[s.project_id] = {
          projectId: s.project_id,
          projectName: s.project_name,
          sessionCount: 0,
          insightCounts: { summary: 0, decision: 0, learning: 0, prompt_quality: 0 },
          totalInputTokens: 0,
          totalOutputTokens: 0,
          estimatedCostUsd: 0,
        };
      }
      statsMap[s.project_id].sessionCount++;
      statsMap[s.project_id].totalInputTokens += s.total_input_tokens ?? 0;
      statsMap[s.project_id].totalOutputTokens += s.total_output_tokens ?? 0;
      statsMap[s.project_id].estimatedCostUsd += s.estimated_cost_usd ?? 0;
    }

    for (const i of insights) {
      if (statsMap[i.project_id]) {
        const type = i.type === 'technique' ? 'learning' : i.type;
        if (type in statsMap[i.project_id].insightCounts) {
          statsMap[i.project_id].insightCounts[type as keyof typeof statsMap[string]['insightCounts']]++;
        }
      }
    }

    return Object.values(statsMap).sort((a, b) => b.sessionCount - a.sessionCount);
  }, [sessions, insights]);

  // Model distribution
  const modelDistribution = useMemo(() => {
    const dist: Record<string, number> = {};
    for (const s of sessions) {
      if (s.primary_model) {
        dist[s.primary_model] = (dist[s.primary_model] ?? 0) + 1;
      }
    }
    return dist;
  }, [sessions]);

  const totalSessions = sessions.length;
  const totalInsights = insights.length;
  const totalCost = sessions.reduce((sum, s) => sum + (s.estimated_cost_usd ?? 0), 0);
  const totalTokens = sessions.reduce(
    (sum, s) =>
      sum +
      (s.total_input_tokens ?? 0) +
      (s.total_output_tokens ?? 0) +
      (s.cache_creation_tokens ?? 0) +
      (s.cache_read_tokens ?? 0),
    0
  );

  // Top projects chart data
  const projectChartData = projectStats
    .slice(0, 10)
    .map((p) => ({
      name: p.projectName.length > 15 ? p.projectName.slice(0, 15) + '...' : p.projectName,
      sessions: p.sessionCount,
    }));

  const hasError = sessionsError || insightsError || projectsError;

  if (hasError && !loading) {
    const retryAll = () => {
      if (sessionsError) refetchSessions();
      if (insightsError) refetchInsights();
      if (projectsError) refetchProjects();
    };
    return (
      <div className="p-6 space-y-6">
        <div>
          <h1 className="text-2xl font-bold">Analytics</h1>
          <p className="text-muted-foreground">Visualize your AI coding usage patterns</p>
        </div>
        <ErrorCard message="Failed to load analytics data" onRetry={retryAll} />
      </div>
    );
  }

  if (loading) {
    return (
      <div className="p-6 space-y-6">
        <div>
          <h1 className="text-2xl font-bold">Analytics</h1>
          <p className="text-muted-foreground">Visualize your AI coding usage patterns</p>
        </div>
        <div className="grid gap-4 md:grid-cols-4">
          {[...Array(4)].map((_, i) => (
            <Card key={i}>
              <CardHeader className="pb-2">
                <Skeleton className="h-4 w-24" />
              </CardHeader>
              <CardContent>
                <Skeleton className="h-8 w-16" />
              </CardContent>
            </Card>
          ))}
        </div>
        <Skeleton className="h-[300px] w-full rounded-lg" />
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      <div>
        <h1 className="text-2xl font-bold">Analytics</h1>
        <p className="text-muted-foreground">Visualize your AI coding usage patterns</p>
      </div>

      {/* Summary Stats */}
      <div className="grid gap-4 md:grid-cols-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Total Sessions</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">{totalSessions}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Total Insights</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">{totalInsights}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Active Projects</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">{projects.length}</div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">
              {totalCost > 0 ? 'Estimated Cost' : 'Total Tokens'}
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">
              {totalCost > 0
                ? `$${totalCost.toFixed(2)}`
                : totalTokens > 0
                  ? formatTokenCount(totalTokens)
                  : '—'}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Activity Over Time */}
      <ActivityChart data={dailyStats} />

      {/* Charts Row */}
      <div className="grid gap-6 md:grid-cols-2">
        <InsightTypeChart data={insightsByType} />

        {/* Sessions by Project */}
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Top Projects</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[200px]">
              {projectChartData.length > 0 ? (
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={projectChartData} layout="vertical">
                    <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
                    <XAxis type="number" tick={{ fontSize: 12 }} />
                    <YAxis
                      type="category"
                      dataKey="name"
                      tick={{ fontSize: 11 }}
                      width={100}
                    />
                    <Tooltip
                      contentStyle={{
                        backgroundColor: tooltipBg,
                        borderColor: tooltipBorder,
                        borderRadius: '8px',
                        fontSize: '12px',
                      }}
                    />
                    <Bar
                      dataKey="sessions"
                      fill={CHART_COLORS.projects.sessions}
                      name="Sessions"
                    />
                  </BarChart>
                </ResponsiveContainer>
              ) : (
                <div className="flex h-full items-center justify-center">
                  <p className="text-sm text-muted-foreground">No project data yet</p>
                </div>
              )}
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Model Distribution */}
      {Object.keys(modelDistribution).length > 0 && (
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Model Distribution</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {Object.entries(modelDistribution)
                .sort(([, a], [, b]) => b - a)
                .map(([model, count], i) => (
                  <div key={model} className="flex items-center gap-3">
                    <div
                      className="h-3 w-3 rounded-full shrink-0"
                      style={{
                        backgroundColor:
                          CHART_COLORS.models[i % CHART_COLORS.models.length],
                      }}
                    />
                    <span className="text-sm flex-1">{formatModelName(model)}</span>
                    <span className="text-sm font-medium">{count}</span>
                    <span className="text-xs text-muted-foreground w-12 text-right">
                      {totalSessions > 0
                        ? `${Math.round((count / totalSessions) * 100)}%`
                        : '—'}
                    </span>
                  </div>
                ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Project Table */}
      <Card>
        <CardHeader>
          <CardTitle className="text-base">All Projects</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead>
                <tr className="border-b">
                  <th className="py-3 text-left font-medium">Project</th>
                  <th className="py-3 text-right font-medium">Sessions</th>
                  <th className="py-3 text-right font-medium">Summaries</th>
                  <th className="py-3 text-right font-medium">Decisions</th>
                  <th className="py-3 text-right font-medium">Learnings</th>
                  <th className="py-3 text-right font-medium">Est. Cost</th>
                  <th className="py-3 text-right font-medium">Tokens</th>
                </tr>
              </thead>
              <tbody>
                {projectStats.map((project) => {
                  const tokens =
                    project.totalInputTokens + project.totalOutputTokens;
                  return (
                    <tr key={project.projectId} className="border-b last:border-0">
                      <td className="py-3">{project.projectName}</td>
                      <td className="py-3 text-right">{project.sessionCount}</td>
                      <td className="py-3 text-right">{project.insightCounts.summary}</td>
                      <td className="py-3 text-right">{project.insightCounts.decision}</td>
                      <td className="py-3 text-right">{project.insightCounts.learning}</td>
                      <td className="py-3 text-right">
                        {project.estimatedCostUsd > 0
                          ? `$${project.estimatedCostUsd.toFixed(2)}`
                          : '—'}
                      </td>
                      <td className="py-3 text-right">
                        {tokens > 0 ? formatTokenCount(tokens) : '—'}
                      </td>
                    </tr>
                  );
                })}
                {projectStats.length === 0 && (
                  <tr>
                    <td colSpan={7} className="py-8 text-center text-muted-foreground text-sm">
                      No project data yet. Sync sessions to see analytics.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

