  1→import { Card, CardContent } from '@/components/ui/card';
  2→import {
  3→  Tooltip,
  4→  TooltipContent,
  5→  TooltipTrigger,
  6→} from '@/components/ui/tooltip';
  7→import { formatDurationMinutes, formatModelName, formatTokenCount } from '@/lib/utils';
  8→import {
  9→  MessageSquare,
 10→  Wrench,
 11→  Clock,
 12→  FolderOpen,
 13→  Zap,
 14→  Coins,
 15→  DollarSign,
 16→  Cpu,
 17→} from 'lucide-react';
 18→
 19→interface StatsHeroProps {
 20→  totalSessions: number;
 21→  totalMessages: number;
 22→  totalToolCalls: number;
 23→  totalDurationMin: number;
 24→  totalProjects: number;
 25→  isExact: boolean;
 26→  totalTokens?: number;
 27→  totalCost?: number;
 28→  topModel?: string | null;
 29→  tokenBreakdown?: {
 30→    inputTokens: number;
 31→    outputTokens: number;
 32→    cacheCreationTokens: number;
 33→    cacheReadTokens: number;
 34→  };
 35→}
 36→
 37→function formatCompact(n: number): string {
 38→  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
 39→  if (n >= 10_000) return `${(n / 1_000).toFixed(1)}k`;
 40→  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}k`;
 41→  return n.toString();
 42→}
 43→
 44→export function StatsHero({
 45→  totalSessions,
 46→  totalMessages,
 47→  totalToolCalls,
 48→  totalDurationMin,
 49→  totalProjects,
 50→  isExact,
 51→  totalTokens,
 52→  totalCost,
 53→  topModel,
 54→  tokenBreakdown,
 55→}: StatsHeroProps) {
 56→  const showUsage = (totalTokens ?? 0) > 0 || (totalCost ?? 0) > 0;
 57→
 58→  const coreCell = (
 59→    key: string,
 60→    label: string,
 61→    value: string,
 62→    Icon: React.ElementType
 63→  ) => (
 64→    <div
 65→      key={key}
 66→      className="flex-1 min-w-[100px] px-4 py-3 border-r border-border last:border-r-0"
 67→    >
 68→      <div className="flex items-center gap-1.5 text-muted-foreground mb-1">
 69→        <Icon className="h-3 w-3" />
 70→        <span className="text-[11px] font-medium uppercase tracking-wide">{label}</span>
 71→      </div>
 72→      <div className="text-lg font-bold text-primary">{value}</div>
 73→    </div>
 74→  );
 75→
 76→  return (
 77→    <Card>
 78→      <CardContent className="p-0">
 79→        <div className="flex flex-wrap">
 80→          {coreCell('sessions', 'Sessions', formatCompact(totalSessions), Zap)}
 81→          {coreCell('messages', 'Messages', `${!isExact ? '~' : ''}${formatCompact(totalMessages)}`, MessageSquare)}
 82→          {coreCell('toolCalls', 'Tool Calls', `${!isExact ? '~' : ''}${formatCompact(totalToolCalls)}`, Wrench)}
 83→          {coreCell('duration', 'Coding Time', `${!isExact ? '~' : ''}${formatDurationMinutes(totalDurationMin)}`, Clock)}
 84→          <div
 85→            className={`flex-1 min-w-[100px] px-4 py-3 ${showUsage ? 'border-r border-border' : ''}`}
 86→          >
 87→            <div className="flex items-center gap-1.5 text-muted-foreground mb-1">
 88→              <FolderOpen className="h-3 w-3" />
 89→              <span className="text-[11px] font-medium uppercase tracking-wide">Projects</span>
 90→            </div>
 91→            <div className="text-lg font-bold text-primary">{totalProjects}</div>
 92→          </div>
 93→
 94→          {showUsage && (
 95→            <>
 96→              <div className="flex-1 min-w-[100px] px-4 py-3 border-r border-border last:border-r-0">
 97→                <div className="flex items-center gap-1.5 text-muted-foreground mb-1">
 98→                  <Coins className="h-3 w-3" />
 99→                  <span className="text-[11px] font-medium uppercase tracking-wide">Tokens</span>
100→                </div>
101→                {tokenBreakdown ? (
102→                  <Tooltip>
103→                    <TooltipTrigger asChild>
104→                      <div
105→                        className="text-lg font-bold text-primary cursor-default"
106→                        aria-label="Token breakdown"
107→                      >
108→                        {formatTokenCount(totalTokens ?? 0)}
109→                      </div>
110→                    </TooltipTrigger>
111→                    <TooltipContent side="bottom" className="text-xs space-y-0.5">
112→                      <p>Input: {formatTokenCount(tokenBreakdown.inputTokens)}</p>
113→                      <p>Output: {formatTokenCount(tokenBreakdown.outputTokens)}</p>
114→                      <p>Cache Write: {formatTokenCount(tokenBreakdown.cacheCreationTokens)}</p>
115→                      <p>Cache Read: {formatTokenCount(tokenBreakdown.cacheReadTokens)}</p>
116→                    </TooltipContent>
117→                  </Tooltip>
118→                ) : (
119→                  <div className="text-lg font-bold text-primary">
120→                    {formatTokenCount(totalTokens ?? 0)}
121→                  </div>
122→                )}
123→              </div>
124→
125→              <div className="flex-1 min-w-[100px] px-4 py-3 border-r border-border last:border-r-0">
126→                <div className="flex items-center gap-1.5 text-muted-foreground mb-1">
127→                  <DollarSign className="h-3 w-3" />
128→                  <span className="text-[11px] font-medium uppercase tracking-wide">Cost</span>
129→                </div>
130→                <div className="text-lg font-bold text-primary">
131→                  ${(totalCost ?? 0).toFixed(2)}
132→                </div>
133→              </div>
134→
135→              {topModel && (
136→                <div className="flex-1 min-w-[100px] px-4 py-3 last:border-r-0">
137→                  <div className="flex items-center gap-1.5 text-muted-foreground mb-1">
138→                    <Cpu className="h-3 w-3" />
139→                    <span className="text-[11px] font-medium uppercase tracking-wide">Top Model</span>
140→                  </div>
141→                  <div className="text-lg font-bold text-primary">
142→                    {formatModelName(topModel)}
143→                  </div>
144→                </div>
145→              )}
146→            </>
147→          )}
148→        </div>
149→      </CardContent>
150→    </Card>
151→  );
152→}
