  1→import { useMemo } from 'react';
  2→import {
  3→  AreaChart,
  4→  Area,
  5→  XAxis,
  6→  YAxis,
  7→  CartesianGrid,
  8→  Tooltip,
  9→  ResponsiveContainer,
 10→} from 'recharts';
 11→import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
 12→import { Button } from '@/components/ui/button';
 13→import { useThemeColors } from '@/lib/hooks/useThemeColors';
 14→import { CHART_COLORS } from '@/lib/constants/colors';
 15→import type { DailyStats } from '@/lib/types';
 16→
 17→type DashboardRange = '7d' | '30d' | '90d' | 'all';
 18→
 19→interface DashboardActivityChartProps {
 20→  data: DailyStats[];
 21→  range: DashboardRange;
 22→  onRangeChange: (range: DashboardRange) => void;
 23→}
 24→
 25→const rangeOptions: { value: DashboardRange; label: string }[] = [
 26→  { value: '7d', label: '7d' },
 27→  { value: '30d', label: '30d' },
 28→  { value: '90d', label: '90d' },
 29→  { value: 'all', label: 'All' },
 30→];
 31→
 32→export function DashboardActivityChart({ data, range, onRangeChange }: DashboardActivityChartProps) {
 33→  const { tooltipBg, tooltipBorder } = useThemeColors();
 34→
 35→  const chartData = useMemo(
 36→    () =>
 37→      data.map((d) => ({
 38→        ...d,
 39→        date: new Date(d.date).toLocaleDateString('en-US', {
 40→          month: 'short',
 41→          day: 'numeric',
 42→        }),
 43→        // Normalize field names to match recharts dataKey
 44→        sessionCount: d.session_count,
 45→        insightCount: d.insight_count,
 46→      })),
 47→    [data]
 48→  );
 49→
 50→  return (
 51→    <Card>
 52→      <CardHeader className="flex flex-row items-center justify-between pb-1">
 53→        <CardTitle className="text-sm font-medium">Activity</CardTitle>
 54→        <div className="flex gap-1">
 55→          {rangeOptions.map(({ value, label }) => (
