 60→              className="h-7 px-2.5 text-xs"
 61→              onClick={() => onRangeChange(value)}
 62→            >
 63→              {label}
 64→            </Button>
 65→          ))}
 66→        </div>
 67→      </CardHeader>
 68→      <CardContent>
 69→        <div className="h-[250px]">
 70→          {chartData.length > 0 ? (
 71→            <ResponsiveContainer width="100%" height="100%">
 72→              <AreaChart data={chartData}>
 73→                <defs>
 74→                  <linearGradient id="dashColorSessions" x1="0" y1="0" x2="0" y2="1">
 75→                    <stop offset="5%" stopColor={CHART_COLORS.activity.sessions} stopOpacity={0.3} />
 76→                    <stop offset="95%" stopColor={CHART_COLORS.activity.sessions} stopOpacity={0} />
 77→                  </linearGradient>
 78→                  <linearGradient id="dashColorInsights" x1="0" y1="0" x2="0" y2="1">
 79→                    <stop offset="5%" stopColor={CHART_COLORS.activity.insights} stopOpacity={0.3} />
 80→                    <stop offset="95%" stopColor={CHART_COLORS.activity.insights} stopOpacity={0} />
 81→                  </linearGradient>
 82→                </defs>
 83→                <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
 84→                <XAxis
 85→                  dataKey="date"
 86→                  tick={{ fontSize: 11 }}
 87→                  tickLine={false}
 88→                  axisLine={false}
 89→                  className="text-muted-foreground"
 90→                  interval={range === '7d' ? 0 : range === '30d' ? 4 : range === '90d' ? 13 : 'preserveStartEnd'}
 91→                />
 92→                <YAxis
 93→                  tick={{ fontSize: 11 }}
 94→                  tickLine={false}
 95→                  axisLine={false}
 96→                  className="text-muted-foreground"
 97→                  width={30}
 98→                />
 99→                <Tooltip
100→                  contentStyle={{
101→                    backgroundColor: tooltipBg,
102→                    borderColor: tooltipBorder,
103→                    borderRadius: '8px',
104→                    fontSize: '12px',
105→                  }}
106→                />
107→                <Area
108→                  type="monotone"
109→                  dataKey="sessionCount"
110→                  name="Sessions"
111→                  stroke={CHART_COLORS.activity.sessions}
112→                  fillOpacity={1}
113→                  fill="url(#dashColorSessions)"
114→                />
115→                <Area
116→                  type="monotone"
117→                  dataKey="insightCount"
118→                  name="Insights"
119→                  stroke={CHART_COLORS.activity.insights}
120→                  fillOpacity={1}
121→                  fill="url(#dashColorInsights)"
122→                />
123→              </AreaChart>
124→            </ResponsiveContainer>
125→          ) : (
126→            <div className="flex h-full items-center justify-center">
127→              <p className="text-sm text-muted-foreground">No activity data yet</p>
128→            </div>
129→          )}
130→        </div>
131→      </CardContent>
132→    </Card>
133→  );
134→}
